css:
.loader {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #0ea5e9);
   position: relative;
   animation: l5-0 2s infinite linear;
}
.loader:before  {
  content: "";
   position: absolute;
   inset: 0;
   background: var(--loader-secondary-color, #67e8f9);
   transform: translate(30px) rotate(0);
   animation: l5-1 .5s infinite }
@keyframes l5-0  {
  100% {transform: rotate(1turn)}
}
@keyframes l5-1  {
  100% {transform: translate(30px) rotate(.25turn)}
}
